The 3D model of the house is now rendered. You can interact with it by rotating, zooming, and panning using your mouse.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            left: 10px;
            color: white;
            font-family: sans-serif;
            background: rgba(0,0,0,0.5);
            padding: 10px;
            border-radius: 5px;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">
        <strong>3D House Model</strong><br>
        Left Click: Rotate<br>
        Right Click: Pan<br>
        Scroll: Zoom
    </div>
    <script type="module">
        import * as THREE from 'https://unpkg.com/three@0.160.0/build/three.module.js';
        import { OrbitControls } from 'https://unpkg.com/three@0.160.0/examples/jsm/controls/OrbitControls.js';

        // Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 15);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.target.set(0, 2, 0);

        // Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xffffff });
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 });
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0x87CEEB, transparent: true, opacity: 0.6 });
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x8B0000 });
        const grassMaterial = new THREE.MeshStandardMaterial({ color: 0x228B22 });

        // Ground
        const groundGeometry = new THREE.PlaneGeometry(100, 100);
        const ground = new THREE.Mesh(groundGeometry, grassMaterial);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // House Group
        const houseGroup = new THREE.Group();

        // Walls
        const wallGeometry = new THREE.BoxGeometry(6, 4, 6);
        const walls = new THREE.Mesh(wallGeometry, wallMaterial);
        walls.position.y = 2;
        walls.castShadow = true;
        walls.receiveShadow = true;
        houseGroup.add(walls);

        // Roof
        const roofGeometry = new THREE.ConeGeometry(5, 3, 4);
        const roof = new THREE.Mesh(roofGeometry, roofMaterial);
        roof.position.y = 5.5;
        roof.rotation.y = Math.PI / 4;
        roof.castShadow = true;
        houseGroup.add(roof);

        // Windows
        const windowGeometry = new THREE.BoxGeometry(1.5, 1.5, 0.2);
        const window1 = new THREE.Mesh(windowGeometry, windowMaterial);
        window1.position.set(1.5, 2.5, 2.9);
        window1.castShadow = true;
        houseGroup.add(window1);

        const window2 = new THREE.Mesh(windowGeometry, windowMaterial);
        window2.position.set(-1.5, 2.5, 2.9);
        window2.castShadow = true;
        houseGroup.add(window2);

        // Door
        const doorGeometry = new THREE.BoxGeometry(1.5, 2.5, 0.2);
        const door = new THREE.Mesh(doorGeometry, doorMaterial);
        door.position.set(0, 1.25, 2.9);
        door.castShadow = true;
        houseGroup.add(door);

        // Front Porch
        const porchGeometry = new THREE.BoxGeometry(6, 0.5, 2);
        const porch = new THREE.Mesh(porchGeometry, wallMaterial);
        porch.position.set(0, 0.25, 3);
        porch.receiveShadow = true;
        houseGroup.add(porch);

        // Porch Roof
        const porchRoofGeometry = new THREE.BoxGeometry(6.5, 0.5, 2.5);
        const porchRoof = new THREE.Mesh(porchRoofGeometry, roofMaterial);
        porchRoof.position.set(0, 1.5, 3);
        porchRoof.castShadow = true;
        houseGroup.add(porchRoof);

        scene.add(houseGroup);

        // Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
